svg.script:
(async function() {
  const frame = document.getElementById('dominum-frame');
  const svgUrl = new URL(window.location.href);
  const repoBase = svgUrl.href.substring(0, svgUrl.href.lastIndexOf('/') + 1);
  const indexUrl = repoBase + 'index.html';

  async function loadAsBlob(url, targetFrame) {
    try {
      const response = await fetch(url);
      if (!response.ok) throw new Error("Fetch failed");
      let html = await response.text();

      const parser = new DOMParser();
      const doc = parser.parseFromString(html, 'text/html');

      if (url.includes('index.html')) {
        const newTitle = doc.querySelector('title')?.innerText;
        if (newTitle) document.title = newTitle;

        const icon = doc.querySelector('link[rel*="icon"]')?.href;
        if (icon) {
          let link = document.querySelector("link[rel*='icon']") || document.createElement('link');
          link.rel = 'shortcut icon';
          link.href = icon;
          document.head.appendChild(link);
        }
      }

      const interceptor = `
        <script>
          document.addEventListener('click', async (e) => {
            const a = e.target.closest('a');
            if (a && a.href && a.href.startsWith('${repoBase}') && !a.target) {
              e.preventDefault();
              window.location.hash = a.href.replace('${repoBase}', '');
              window.parent.postMessage({type: 'NAVIGATE', url: a.href}, '*');
            }
          });
        <\/script>
      `;

      const baseTag = `<base href="${repoBase}">`;
      html = html.replace('<head>', '<head>' + baseTag + interceptor);

      const blob = new Blob([html], { type: 'text/html' });
      targetFrame.src = URL.createObjectURL(blob);
    } catch (e) {
      targetFrame.srcdoc = "<h2 style='color:white;text-align:center;margin-top:20%;'>Error loading content.</h2>";
    }
  }

  window.addEventListener('message', (event) => {
    if (event.data.type === 'NAVIGATE') {
      loadAsBlob(event.data.url, frame);
    }
  });

  // Initial Load
  loadAsBlob(indexUrl, frame);
})();
